def compute_score() -> tuple[str, float]:
    from pptx import Presentation

    if len(ppt_diff.added_slides) != 1:
        return "Cannot evaluate content - no single slide was added", 0.0

    prs = Presentation(modified_ppt_path)

    # Find the slide with 'Traditional Weapons' title
    target_slide = None
    for slide in prs.slides:
        for shape in slide.shapes:
            if hasattr(shape, 'text') and 'Traditional Weapons' in shape.text:
                target_slide = slide
                break
        if target_slide:
            break

    if not target_slide:
        return "Cannot find slide with Traditional Weapons title", 0.0

    # Extract all text from the slide
    slide_text = ""
    for shape in target_slide.shapes:
        if hasattr(shape, 'text'):
            slide_text += shape.text + " "

    slide_text = slide_text.strip()

    if len(slide_text) == 0 or slide_text.lower() == 'traditional weapons':
        return "Slide has minimal content - just the title", 0.5

    # Use LLM to evaluate content appropriateness
    prompt = f"""Evaluate if the following slide content is appropriate for a presentation about Pre-Colonial Filipino Culture, specifically for a slide titled 'Traditional Weapons'.

    Slide content: {slide_text}

    Rate the appropriateness on a scale of 0-1 where:
    - 1.0: Highly relevant and appropriate content about pre-colonial Filipino traditional weapons
    - 0.8: Mostly relevant content with minor issues
    - 0.6: Somewhat relevant but could be more specific to Filipino culture
    - 0.4: Generic content about weapons, not specifically Filipino
    - 0.2: Barely relevant content
    - 0.0: Completely inappropriate or irrelevant content

    Respond with just the score (0.0 to 1.0) and a brief reason."""

    response = llm_call(prompt, temperature=0.3)

    try:
        # Extract score from response
        import re
        score_match = re.search(r'([0-1]\.[0-9]+|[0-1])', response)
        if score_match:
            score = float(score_match.group(1))
            return f"Content appropriateness evaluated: {response.strip()}", score
        else:
            return f"Could not parse score from LLM response: {response}", 0.5
    except:
        return f"Error evaluating content appropriateness: {response}", 0.5

